update users
set login_attempts = login_attempts + 1, updated_at = now()
where id = #{id}

update users
set locked_until = date_add(now(), interval 30 minute), updated_at = now()
where id = #{id}

update users
set locked_until = null, login_attempts = 0, updated_at = now()
where id = #{id}

