mapper.select:
select count(1)
from users u
left join roles r on r.code = u.role
left join departments d on d.id = u.department_id


        and u.name like concat('%', #{name}, '%')


        and u.role = #{role}


        and d.name like concat('%', #{department}, '%')


        and u.department_id = #{departmentId}


        and u.is_active = #{isActive}

select u.*, r.name as role_name, d.name as department
from users u
left join roles r on r.code = u.role
left join departments d on d.id = u.department_id


        and u.name like concat('%', #{name}, '%')


        and u.role = #{role}


        and d.name like concat('%', #{department}, '%')


        and u.department_id = #{departmentId}


        and u.is_active = #{isActive}


order by u.id desc
limit #{offset}, #{size}
